import styled from "@emotion/styled";
import { Button } from "@leafygreen-ui/button";
import { Disclaimer } from "@leafygreen-ui/typography";
import { size } from "../../constants/tokens";
import usePagination from "../../hooks/usePagination";
import Icon from "../Icon";

interface Props {
  countLimit?: number;
  currentPage: number;
  onChange?: (i: number) => void;
  totalResults: number;
  pageSize: number;
}

/**
 * Pagination component for navigating between pages of data
 * By default it will update the page query param in the URL
 * @param props - React props passed to the component
 * @param props.countLimit - optional count for the max value that was queried for. Used to display "many" instead of an exact number
 * @param props.currentPage - the current page
 * @param props.onChange - optional callback for when the page changes (Will override the default behavior of updating the URL query param)
 * @param props.totalResults - total number of results
 * @param props.pageSize - maximum number of results per page
 * @returns The Pagination component
 */
const Pagination: React.FC<Props> = ({
  countLimit,
  currentPage,
  onChange,
  pageSize,
  totalResults,
}) => {
  const { setPage } = usePagination();
  const handleChange = onChange || setPage;
  const numPages = Math.ceil(totalResults / pageSize);

  const handlePrevClick = () => {
    handleChange(currentPage - 1);
  };
  const handleNextClick = () => {
    handleChange(currentPage + 1);
  };

  const denominator =
    countLimit && totalResults >= countLimit ? "many" : numPages;

  return (
    <Container data-cy="pagination">
      <StyledButton
        data-cy="prev-page-button"
        disabled={currentPage === 0}
        leftGlyph={<Icon glyph="ChevronLeft" size="small" />}
        onClick={handlePrevClick}
        size="small"
      />
      <PageLabel>
        <Disclaimer>
          {numPages > 0 ? currentPage + 1 : 0} / {denominator}
        </Disclaimer>
      </PageLabel>
      <StyledButton
        data-cy="next-page-button"
        disabled={numPages === 0 || currentPage === numPages - 1}
        leftGlyph={<Icon glyph="ChevronRight" size="small" />}
        onClick={handleNextClick}
        size="small"
      />
    </Container>
  );
};

const StyledButton = styled(Button)`
  margin-right: ${size.xxs};
  margin-left: ${size.xxs};
`;

const PageLabel = styled.div`
  width: 48px;
  text-align: center;
`;

const Container = styled.div`
  align-items: center;
  display: flex;
  flex-shrink: 0;
`;

export default Pagination;

export enum TaskStatus {
  Inactive = "inactive",

  // TaskUnstarted is assigned to a display task after cleaning up one of
  // its execution tasks. This indicates that the display task is
  // pending a rerun
  Unstarted = "unstarted",

  // TaskUndispatched indicates either
  //  1. a task is not scheduled to run (when Task.Activated == false)
  //  2. a task is scheduled to run (when Task.Activated == true)
  Undispatched = "undispatched",
  WillRun = "will-run",
  Unscheduled = "unscheduled",

  // TaskStarted indicates a task is currently running
  Started = "started",

  // TaskDispatched indicates that an agent has received the task, but
  // the agent has not yet told Evergreen that it's running the task
  Dispatched = "dispatched",

  // This is a temporary status which is the same as undispatched, but
  // with the additional info that it's waiting for a dependency
  Pending = "pending",

  // The statuses below indicate that a task has finished.
  Succeeded = "success",

  // These statuses indicate that the task failed, and it is likely a problem
  // with the code being tested
  Failed = "failed",
  TestTimedOut = "test-timed-out",
  TaskTimedOut = "task-timed-out",

  // These statuses indicate that the task failed, and it is likely a problem
  // with the systems running the task
  SetupFailed = "setup-failed",
  SystemFailed = "system-failed",
  SystemTimedOut = "system-timed-out",
  SystemUnresponsive = "system-unresponsive",

  // This status means that the task will not run because a dependency was
  // not satisfied
  Blocked = "blocked",
  Aborted = "aborted",

  KnownIssue = "known-issue",
}

// Task status sorted in order of "relevance", with the most likely actionable at the top.
export const SortedTaskStatus = [
  TaskStatus.Failed,
  TaskStatus.TestTimedOut,
  TaskStatus.TaskTimedOut,
  TaskStatus.KnownIssue,
  TaskStatus.SetupFailed,
  TaskStatus.SystemFailed,
  TaskStatus.SystemTimedOut,
  TaskStatus.SystemUnresponsive,
  TaskStatus.Started,
  TaskStatus.Dispatched,
  TaskStatus.Succeeded,
  TaskStatus.Undispatched,
  TaskStatus.WillRun,
  TaskStatus.Aborted,
  TaskStatus.Blocked,
  TaskStatus.Unscheduled,
];

export enum TaskStatusUmbrella {
  Failed = "failed-umbrella",
  SystemFailure = "system-failure-umbrella",
  Running = "running-umbrella",
  Undispatched = "undispatched-umbrella",
  Scheduled = "scheduled-umbrella",
}

export enum TestStatus {
  Fail = "fail",
  Skip = "skip",
  SilentFail = "silentfail",
  Pass = "pass",
}

