  children,
  "data-cy": dataCy,
  ...rest
}) => (
  <StyledTooltip
    align="top"
    justify="middle"
    trigger={
      <IconWrapper data-cy={dataCy}>
        <Icon {...rest} />
      </IconWrapper>
    }
    triggerEvent="hover"
  >
    {children}
  </StyledTooltip>
);

const StyledTooltip = styled(
  Tooltip as React.ComponentType<Partial<TooltipProps>>,
)`
  max-width: 300px;
`;

