import { useRef, useState } from 'react';
import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import { Button } from '@leafygreen-ui/button';
import Popconfirm from '.';

const meta = {
  component: Popconfirm,
  tags: ['ai-generated', 'needs-work'],
} satisfies Meta<typeof Popconfirm>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Default: Story = {
  render: (args) => {
    const triggerRef = useRef<HTMLButtonElement>(null);
    const [open, setOpen] = useState(false);
    return (
      <div style={{ padding: 100 }}>
        <Button ref={triggerRef} onClick={() => setOpen(true)}>
          Delete item
        </Button>
        <Popconfirm
          {...args}
          open={open}
          refEl={triggerRef.current ?? undefined}
          setOpen={setOpen}
        >
          Are you sure you want to delete this item?
        </Popconfirm>
      </div>
    );
  },
  play: async ({ canvas, userEvent }) => {
    await userEvent.click(canvas.getByRole('button', { name: /delete item/i }));
    await expect(await canvas.findByText(/are you sure/i)).toBeVisible();
  },
};

export const CustomConfirmText: Story = {
  render: (args) => {
    const triggerRef = useRef<HTMLButtonElement>(null);
    const [open, setOpen] = useState(true);
    return (
      <div style={{ padding: 100 }}>
        <Button ref={triggerRef}>Remove</Button>
        <Popconfirm
          {...args}
          confirmText="Confirm Delete"
          open={open}
          refEl={triggerRef.current ?? undefined}
          setOpen={setOpen}
        >
          This action cannot be undone.
        </Popconfirm>
      </div>
    );
  },
};

