 80→    case TaskStatus.SystemFailed:
 81→    case TaskStatus.SystemUnresponsive:
 82→    case TaskStatus.SystemTimedOut:
 83→      return {
 84→        border: purple.dark3,
 85→        fill: purple.dark2,
 86→        text: purple.light3,
 87→      };
 88→    case TaskStatus.KnownIssue:
 89→      return {
 90→        border: red.light2,
 91→        fill: white,
 92→        text: red.dark2,
 93→      };
 94→    default:
 95→      return {};
 96→  }
